// WF_SCENE_IMAGE_PROCESSOR / Generate Scene Image
// v3 (2026-05-01): hybrid model routing, no illustration suffix, full data preservation.
//
// Routing:
//   requires_text_rendering=true OR keyword match â†’ openai/gpt-5-image-mini
//     (OpenRouter, $0.045/img, native text rendering)
//     fallback â†’ google/gemini-3-pro-image-preview (OpenRouter, $0.069/img)
//   else â†’ fal-ai/flux/schnell (Fal.ai, $0.003/img, fast photoreal)
//
// All upstream intelligence (composition_prefix + image_prompt + registerAnchors
// + styleDna + negative_prompt) is forwarded verbatim to the chosen model.
// Resolved prompt + chosen model + cost are persisted to scenes + production_log
// so nothing is lost downstream.

const { execSync } = require('child_process');
const body = $('Webhook Trigger').first().json.body || {};
const sceneId = body.scene_id;
const sceneNumber = body.scene_number || 0;
const paddedNum = sceneNumber.toString().padStart(3, '0');
const topicId = body.topic_id;
const projectId = body.project_id;
const promptIn = (body.image_prompt || '').toString();
const negativePrompt = body.negative_prompt || '';
const requiresTextFlag = body.requires_text_rendering === true;

// Keyword fallback for legacy scenes (where requires_text_rendering flag is missing).
// TIGHT phrase matches only â€” generic words like 'magazine' or 'chart' are stylistic
// fluff in many script-gen prompts and would over-route. Trust requires_text_rendering
// flag from script-gen as primary; this fallback catches obvious-text-needed legacy scenes.
const TEXT_KEYWORDS = [
  // Named programs (text always present on the rendered prop)
  'mygov', 'medicare card', 'healthcare card', 'commonwealth seniors',
  'centrelink form', 'centrelink letter', 'centrelink statement',
  // Document types
  'application form', 'tax form', 'tax statement', 'tax return',
  'benefits letter', 'pension form', 'invoice', 'receipt',
  // UI elements (have text by definition)
  'login page', 'login screen', 'web page', 'webpage', 'screenshot',
  'spreadsheet', 'app interface', 'dashboard interface',
  // Print/news with visible headlines
  'magazine cover', 'newspaper headline', 'newspaper front page',
  'breaking news headline', 'price tag', 'price chart', 'pricing chart',
  // Educational binders/booklets where label text drives meaning
  'training materials', 'training brochure', 'training binder',
  'brochure cover', 'booklet cover',
  // Comparison/breakdown charts (PBS, ATO, cost analyses â€” text-driven)
  'pbs pricing', 'pbs price', 'pricing structure', 'pricing breakdown',
  'price comparison', 'cost comparison', 'cost breakdown', 'savings calculation',
  'rate comparison', 'rate chart', 'safety net threshold',
  'eligibility chart', 'income threshold', 'asset test'
];
const promptLower = promptIn.toLowerCase();
const keywordHit = TEXT_KEYWORDS.find(function(k) { return promptLower.indexOf(k) !== -1; }) || null;
const useTextModel = requiresTextFlag || !!keywordHit;

console.log('[scene ' + sceneNumber + '] requires_text=' + requiresTextFlag + ' keywordHit=' + (keywordHit || 'none') + ' useTextModel=' + useTextModel + ' promptLen=' + promptIn.length);

let modelUsed = '';
let imageUrl = '';
let costUsd = 0;
let providerError = null;
const startTime = Date.now();

async function callOpenRouter(modelName, prompt) {
  const resp = await fetch('https://openrouter.ai/api/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + $env.OPENROUTER_API_KEY,
      'Content-Type': 'application/json',
      'HTTP-Referer': 'https://dashboard.operscale.cloud',
      'X-Title': 'Vision GridAI Scene Images'
    },
    body: JSON.stringify({
      model: modelName,
      messages: [{ role: 'user', content: prompt + ' Render in landscape 16:9 aspect ratio.' }],
      modalities: ['image', 'text']
    })
  });
  const result = await resp.json();
  if (result.error) return { error: result.error };
  const msg = (result.choices && result.choices[0] && result.choices[0].message) || {};
  if (!msg.images || !msg.images[0] || !msg.images[0].image_url || !msg.images[0].image_url.url) {
    return { error: { refusal: (msg.content || msg.refusal || '').toString().substring(0, 300) } };
  }
  const dataUrl = msg.images[0].image_url.url;
  const b64 = dataUrl.indexOf(',') >= 0 ? dataUrl.split(',', 2)[1] : dataUrl;
  const cost = (result.usage && result.usage.cost) || 0.05;
  return { b64: b64, cost: cost };
}

function saveB64ToScenePath(b64) {
  const dir = '/tmp/production/' + topicId + '/scene_images';
  execSync('mkdir -p ' + dir, { shell: '/bin/sh' });
  const rawPath = dir + '/raw_' + paddedNum + '.png';
  const outPath = dir + '/scene_' + paddedNum + '.png';
  execSync('base64 -d > ' + rawPath, { shell: '/bin/sh', input: b64, maxBuffer: 50 * 1024 * 1024, timeout: 15000 });
  // Crop/resize to 1280x720 landscape so downstream Ken Burns gets uniform input
  execSync('ffmpeg -y -i ' + rawPath + ' -vf "scale=1280:720:force_original_aspect_ratio=increase,crop=1280:720" ' + outPath + ' 2>&1', { shell: '/bin/sh', timeout: 20000 });
  try { execSync('rm -f ' + rawPath, { shell: '/bin/sh' }); } catch(e) {}
  // URL the n8n container can fetch from later (http.server :9999 is bound to /data/n8n-production)
  return 'http://172.18.0.1:9999/' + topicId + '/scene_images/scene_' + paddedNum + '.png';
}

try {
  if (useTextModel) {
    modelUsed = 'openai/gpt-5-image-mini';
    let r = await callOpenRouter(modelUsed, promptIn);
    if (r.error) {
      console.log('gpt-5-image-mini fallback to gemini-3-pro: ' + JSON.stringify(r.error).substring(0, 200));
      modelUsed = 'google/gemini-3-pro-image-preview';
      r = await callOpenRouter(modelUsed, promptIn);
      if (r.error) throw new Error('Both text models failed: ' + JSON.stringify(r.error).substring(0, 300));
    }
    imageUrl = saveB64ToScenePath(r.b64);
    costUsd = r.cost;
  } else {
    modelUsed = 'fal-ai/flux/schnell';
    const resp = await fetch('https://fal.run/fal-ai/flux/schnell', {
      method: 'POST',
      headers: { 'Authorization': 'Key ' + $env.FAL_API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        prompt: promptIn,
        negative_prompt: negativePrompt,
        image_size: 'landscape_16_9',
        num_inference_steps: 4
      })
    });
    const result = await resp.json();
    if (!result.images || !result.images[0]) throw new Error('Flux Schnell empty: ' + JSON.stringify(result).substring(0, 300));
    imageUrl = result.images[0].url;
    costUsd = 0.003;
  }
} catch (err) {
  providerError = err.message || String(err);
  console.log('[scene ' + sceneNumber + '] PROVIDER ERROR: ' + providerError);
}

const elapsedMs = Date.now() - startTime;

// Persist resolved prompt + model + cost on the scene row (full provenance preserved)
try {
  await fetch($env.SUPABASE_URL + '/rest/v1/scenes?id=eq.' + sceneId, {
    method: 'PATCH',
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      image_prompt_resolved: promptIn.substring(0, 8000),
      image_model: modelUsed,
      image_cost_usd: Math.round(costUsd * 100000) / 100000
    })
  });
} catch (e) { /* non-fatal */ }

// Append to production_log so we have a forensic trail of every image call
try {
  await fetch($env.SUPABASE_URL + '/rest/v1/production_log', {
    method: 'POST',
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'image',
      action: providerError ? 'failed' : 'completed',
      details: {
        scene_id: sceneId,
        scene_number: sceneNumber,
        model: modelUsed,
        prompt_resolved_preview: promptIn.substring(0, 600),
        prompt_length: promptIn.length,
        requires_text: useTextModel,
        keyword_hit: keywordHit,
        cost_usd: costUsd,
        elapsed_ms: elapsedMs,
        error: providerError,
        image_url: imageUrl,
        register_id: body.register_id,
        color_mood: body.color_mood,
        zoom_direction: body.zoom_direction,
        composition_prefix: body.composition_prefix
      }
    })
  });
} catch (e) { /* non-fatal */ }

if (providerError) throw new Error('Image generation failed for scene ' + sceneNumber + ': ' + providerError);

return [{ json: {
  scene_id: sceneId,
  scene_number: sceneNumber,
  image_url: imageUrl,
  model: modelUsed,
  cost_usd: costUsd,
  elapsed_ms: elapsedMs,
  image_status: 'uploaded'
} }];
